const WindowManager={windows:new Map(),dragState:null,resizeState:null,zIndexCounter:100,create(appId,title,icon,content,opts={}){const id=`win_${appId}_${Date.now()}`,w=opts.width||700,h=opts.height||480,x=60+(this.windows.size*30)%200,y=40+(this.windows.size*30)%150;const el=document.createElement('div');el.className='window';el.id=id;el.style.cssText=`width:${w}px;height:${h}px;left:${x}px;top:${y}px;z-index:${++this.zIndexCounter}`;el.innerHTML=`<div class="window-titlebar"><span class="window-icon">${icon}</span><span class="title-text">${title}</span><div class="window-controls"><button class="btn-minimize" title="Minimizar">${renderIcon('minimize',14)}</button><button class="btn-maximize" title="Maximizar/Restaurar">${renderIcon('maximize',14)}</button><button class="btn-close" title="Fechar">${renderIcon('close',14)}</button></div></div><div class="window-content"></div>`;el.querySelector('.window-content').innerHTML=content;document.getElementById('window-container').appendChild(el);const winData={id,appId,title,icon,element:el,minimized:false,maximized:false};this.windows.set(id,winData);this.setupWindowEvents(winData);this.updateTaskbar();SoundManager.play('openWindow');return winData;},setupWindowEvents(winData){const el=winData.element,titlebar=el.querySelector('.window-titlebar'),btnMin=el.querySelector('.btn-minimize'),btnMax=el.querySelector('.btn-maximize'),btnClose=el.querySelector('.btn-close');el.addEventListener('mousedown',()=>{this.focus(winData.id)});titlebar.addEventListener('dblclick',()=>{this.toggleMaximize(winData.id)});btnMin.addEventListener('click',(e)=>{e.stopPropagation();this.minimize(winData.id)});btnMax.addEventListener('click',(e)=>{e.stopPropagation();this.toggleMaximize(winData.id)});btnMax.addEventListener('mouseenter',()=>{SnapManager.showPopup(winData.id,btnMax)});btnMax.addEventListener('mouseleave',()=>{SnapManager.hidePopup()});btnClose.addEventListener('click',(e)=>{e.stopPropagation();this.close(winData.id)});titlebar.addEventListener('mousedown',(e)=>{if(e.target.closest('button'))return;this.dragState={winId:winData.id,startX:e.clientX,startY:e.clientY,origLeft:parseFloat(el.style.left)||0,origTop:parseFloat(el.style.top)||0}});el.querySelectorAll('.window-resize-handle').forEach(h=>{h.addEventListener('mousedown',(e)=>{e.preventDefault();this.resizeState={winId:winData.id,direction:h.className.split(' ').find(c=>['top','bottom','left','right'].includes(c)),startX:e.clientX,startY:e.clientY,origWidth:el.offsetWidth,origHeight:el.offsetHeight,origLeft:parseFloat(el.style.left)||0,origTop:parseFloat(el.style.top)||0}})});},toggleMaximize(id){const winData=this.windows.get(id);if(!winData)return;const el=winData.element;if(winData.maximized){el.style.width=winData.prevSize.width;el.style.height=winData.prevSize.height;el.style.left=winData.prevSize.left;el.style.top=winData.prevSize.top;winData.maximized=false;}else{const tbH=parseInt(getComputedStyle(document.documentElement).getPropertyValue('--taskbar-height')||'48');winData.prevSize={width:el.style.width,height:el.style.height,left:el.style.left,top:el.style.top};el.style.width='calc(100% - 16px)';el.style.height=`calc(100vh - ${tbH + 8}px)`;el.style.left='8px';el.style.top='8px';winData.maximized=true;}SoundManager.play('click');},minimize(id){const winData=this.windows.get(id);if(!winData)return;winData.element.classList.add('minimized');winData.minimized=true;SoundManager.play('minimize');this.updateTaskbar();},restore(id){const winData=this.windows.get(id);if(!winData)return;winData.element.classList.remove('minimized');winData.minimized=false;this.focus(id);SoundManager.play('openWindow');this.updateTaskbar();},close(id){const winData=this.windows.get(id);if(!winData)return;winData.element.remove();this.windows.delete(id);SoundManager.play('closeWindow');this.updateTaskbar();},focus(id){const winData=this.windows.get(id);if(!winData)return;winData.element.style.zIndex=++this.zIndexCounter;if(winData.minimized)this.restore(id);},handleDragMove(e){if(!this.dragState)return;const winData=this.windows.get(this.dragState.winId);if(!winData)return;const dx=e.clientX-this.dragState.startX,dy=e.clientY-this.dragState.startY;winData.element.style.left=`${this.dragState.origLeft+dx}px`;winData.element.style.top=`${this.dragState.origTop+dy}px`;SnapManager.checkSnap(e.clientX,e.clientY);},handleResizeMove(e){if(!this.resizeState)return;const s=this.resizeState,winData=this.windows.get(s.winId);if(!winData)return;const dx=e.clientX-s.startX,dy=e.clientY-s.startY;if(s.direction.includes('right'))winData.element.style.width=`${s.origWidth+dx}px`;if(s.direction.includes('bottom'))winData.element.style.height=`${s.origHeight+dy}px`;if(s.direction.includes('left')){winData.element.style.width=`${s.origWidth-dx}px`;winData.element.style.left=`${s.origLeft+dx}px`;}if(s.direction.includes('top')){winData.element.style.height=`${s.origHeight-dy}px`;winData.element.style.top=`${s.origTop+dy}px`;}},handleDragEnd(){this.dragState=null;SnapManager.hideOverlay();},handleResizeEnd(){this.resizeState=null;},updateTaskbar(){const container=document.getElementById('taskbar-apps');container.innerHTML='';this.windows.forEach(winData=>{const btn=document.createElement('button');btn.className='taskbar-app'+(winData.minimized?' minimized':'');btn.innerHTML=`<span class="task-icon">${winData.icon}</span><span class="task-name">${winData.title}</span>`;btn.addEventListener('click',()=>{if(winData.minimized)this.restore(winData.id);else if(winData.element.style.zIndex==this.zIndexCounter)this.minimize(winData.id);else this.focus(winData.id)});container.appendChild(btn);})}};

