const ParticleEngine={canvas:null,ctx:null,particles:[],enabled:false,type:'glow',density:50,mouseX:0,mouseY:0,animationId:null,init(){this.canvas=document.getElementById('particle-canvas');if(!this.canvas)return;this.ctx=this.canvas.getContext('2d');this.resize();window.addEventListener('resize',()=>this.resize());document.addEventListener('mousemove',(e)=>{this.mouseX=e.clientX;this.mouseY=e.clientY;});this.loadSettings();},resize(){if(!this.canvas)return;this.canvas.width=window.innerWidth;this.canvas.height=window.innerHeight;},loadSettings(){const s=Storage.get('particles',{enabled:false,type:'glow',density:50});this.enabled=s.enabled;this.type=s.type;this.density=s.density;if(this.enabled)this.start();else this.stop();},setOptions(opts){if(opts.enabled!==undefined)this.enabled=opts.enabled;if(opts.type!==undefined)this.type=opts.type;if(opts.density!==undefined)this.density=opts.density;Storage.set('particles',{enabled:this.enabled,type:this.type,density:this.density});if(this.enabled&&this.animationId===null)this.start();else if(!this.enabled&&this.animationId)this.stop();},start(){if(this.animationId||!this.enabled)return;this.animate();},stop(){if(this.animationId){cancelAnimationFrame(this.animationId);this.animationId=null;}this.particles=[];if(this.ctx)this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);},animate(){if(!this.enabled)return;this.update();this.draw();this.animationId=requestAnimationFrame(()=>this.animate());},update(){const count=Math.floor(this.density/10);for(let i=0;i<count;i++){this.particles.push({x:this.mouseX,y:this.mouseY,vx:(Math.random()-0.5)*4,vy:(Math.random()-0.5)*4,life:1,size:Math.random()*3+1,type:this.type});}this.particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.life-=0.02;p.size*=0.98;});this.particles=this.particles.filter(p=>p.life>0);},draw(){if(!this.ctx)return;this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);this.particles.forEach(p=>{this.ctx.globalAlpha=p.life;if(p.type==='glow'){this.ctx.fillStyle='#60a5fa';this.ctx.beginPath();this.ctx.arc(p.x,p.y,p.size,0,Math.PI*2);this.ctx.fill();}else if(p.type==='stars'){this.ctx.fillStyle='#fbbf24';this.ctx.beginPath();this.drawStar(p.x,p.y,5,p.size,p.size/2);this.ctx.fill();}else if(p.type==='matrix'){this.ctx.fillStyle='#22c55e';this.ctx.font='12px monospace';this.ctx.fillText(String.fromCharCode(0x30A0+Math.random()*96),p.x,p.y);}});this.ctx.globalAlpha=1;},drawStar(cx,cy,spikes,outerRadius,innerRadius){let rot=Math.PI/2*3,x=cx,y=cy,step=Math.PI/spikes;this.ctx.moveTo(cx,cy-outerRadius);for(let i=0;i<spikes;i++){x=cx+Math.cos(rot)*outerRadius;y=cy+Math.sin(rot)*outerRadius;this.ctx.lineTo(x,y);rot+=step;x=cx+Math.cos(rot)*innerRadius;y=cy+Math.sin(rot)*innerRadius;this.ctx.lineTo(x,y);rot+=step;}this.ctx.lineTo(cx,cy-outerRadius);this.ctx.closePath();}};

