const FileSystem={defaultFS:{'/':{type:'folder',children:{'Documentos':{type:'folder',children:{'leia-me.txt':{type:'file',content:'Bem-vindo ao GlassOS v1.3!\nEste sistema possui criptografia de pastas.'},'notas.txt':{type:'file',content:'Minhas anotações:\n- Aprender JavaScript\n- Criar projetos'}}},'Imagens':{type:'folder',children:{}},'Downloads':{type:'folder',children:{}}}}},unlockedFolders:new Set(),getFS(){return Storage.get('filesystem',JSON.parse(JSON.stringify(this.defaultFS)));},saveFS(fs){Storage.set('filesystem',fs);},getNode(fs,path){if(path==='/')return fs['/'];const parts=path.split('/').filter(Boolean);let node=fs['/'];for(const part of parts){if(node.children&&node.children[part])node=node.children[part];else return null;}return node;},getParentPath(path){if(path==='/')return'/';const parts=path.split('/').filter(Boolean);parts.pop();return'/'+parts.join('/')||'/';},createItem(fs,path,name,type,content=''){const node=this.getNode(fs,path);if(!node||node.type!=='folder')return false;if(node.children[name])return false;node.children[name]=type==='folder'?{type:'folder',children:{}}:{type:'file',content};this.saveFS(fs);return true;},deleteItem(fs,path,name){const node=this.getNode(fs,path);if(!node||node.type!=='folder'||!node.children[name])return false;delete node.children[name];this.saveFS(fs);return true;},isFolderEncrypted(node){return node.encrypted===true;},unlockFolder(path,password){return new Promise(async(resolve)=>{const fs=this.getFS(),node=this.getNode(fs,path);if(!node||!node.encrypted){resolve(false);return;}const verified=await EncryptionHelper.verifyPassword(password,node.passwordHash);if(verified){this.unlockedFolders.add(path);resolve(true);}else{resolve(false);}});},lockFolder(path){this.unlockedFolders.delete(path);},encryptFolder(path,password){return new Promise(async(resolve)=>{const fs=this.getFS(),node=this.getNode(fs,path);if(!node||node.type!=='folder'){resolve(false);return;}node.encrypted=true;node.passwordHash=await EncryptionHelper.hashPassword(password);this.saveFS(fs);resolve(true);});},decryptFolder(path){return new Promise((resolve)=>{const fs=this.getFS(),node=this.getNode(fs,path);if(!node||!node.encrypted){resolve(false);return;}delete node.encrypted;delete node.passwordHash;this.saveFS(fs);this.unlockedFolders.delete(path);resolve(true);});}};

