const GlobalSearch={fileIndex:{},init(){this.buildFileIndex();},buildFileIndex(){const fs=FileSystem.getFS();this.fileIndex={};this.indexNode(fs['/'],'');},indexNode(node,path){if(!node)return;if(node.type==='folder'){Object.entries(node.children||{}).forEach(([name,child])=>{this.indexNode(child,path+'/'+name);});}else if(node.type==='file'&&/\.(txt|md|log)$/.test(path)){const words=(node.content||'').toLowerCase().split(/\W+/).filter(w=>w.length>2);words.forEach(word=>{if(!this.fileIndex[word])this.fileIndex[word]=[];if(!this.fileIndex[word].includes(path))this.fileIndex[word].push(path);});}},search(query){query=query.toLowerCase();const results={apps:[],files:[],content:[]};const appNames=['Bloco de Notas','Calculadora','Arquivos','Configurações','Terminal','Relógio','Calendário','Gerenciador de Tarefas','Arcade'];appNames.forEach(app=>{if(app.toLowerCase().includes(query))results.apps.push(app);});const fs=FileSystem.getFS();const searchInFolder=(node,path)=>{if(!node)return;if(node.type==='folder'){Object.entries(node.children||{}).forEach(([name,child])=>{searchInFolder(child,path+'/'+name);});}else if(node.type==='file'&&path.toLowerCase().includes(query)){results.files.push(path);}};searchInFolder(fs['/'],'');if(this.fileIndex[query]){this.fileIndex[query].forEach(p=>{if(!results.content.includes(p))results.content.push(p);});};return results;}};

