const NotificationSystem={notifications:[],focusMode:false,show(title,message,type='info',duration=4000){const id=`notif_${Date.now()}`;this.notifications.unshift({id,title,message,type,time:new Date().toLocaleTimeString()});if(this.focusMode&&type!=='urgent')return;const el=document.createElement('div');el.className=`notification toast ${type}`;el.id=id;el.innerHTML=`<div class="toast-content"><strong>${title}</strong><p>${message}</p></div>`;document.getElementById('toast-container').appendChild(el);setTimeout(()=>{el.classList.add('fade-out');setTimeout(()=>el.remove(),300);},duration);this.updateCenter();},updateCenter(){const list=document.getElementById('notification-list');if(!list)return;list.innerHTML=this.notifications.map(n=>`<div class="notification-item ${n.type}"><div class="notif-content"><strong>${n.title}</strong><p>${n.message}</p><span class="notif-time">${n.time}</span></div></div>`).join('')||'<div class="empty-notif">Nenhuma notificação</div>';},clearAll(){this.notifications=[];this.updateCenter();},toggleFocusMode(){this.focusMode=!this.focusMode;}};

