const ClipboardManager={items:[],copy(text){navigator.clipboard.writeText(text);this.items.unshift({text,time:new Date().toLocaleTimeString()});if(this.items.length>20)this.items.pop();Storage.set('clipboard',this.items);this.updatePanel();},updatePanel(){const list=document.getElementById('clipboard-list');if(!list)return;list.innerHTML=this.items.map((item,i)=>`<div class="clipboard-item" data-idx="${i}"><div class="clip-text">${item.text.substring(0,50)}${item.text.length>50?'...':''}</div><span class="clip-time">${item.time}</span></div>`).join('')||'<div class="empty-clip">Área vazia</div>';list.querySelectorAll('.clipboard-item').forEach(item=>{item.onclick=()=>{navigator.clipboard.writeText(this.items[item.dataset.idx].text);SoundManager.play('click');};});},clear(){this.items=[];Storage.set('clipboard',[]);this.updatePanel();},load(){this.items=Storage.get('clipboard',[]);}};

